+/// Show memory status (conversation count, auto-training progress)
+fn showMemoryStatus(allocator: std.mem.Allocator, model_path_opt: ?[]const u8) !void {
+    const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+
+    if (model_path_opt) |model_path| {
+        // Show status for specific model
+        try validateModelPath(model_path);
+
+        // Load model to get hash
+        const prof = optimizer.loadOptimizedProfile(allocator, model_path) catch {
+            std.debug.print("Error: Model not built. Run 'zell build {s}' first.\n", .{model_path});
+            return error.ModelNotBuilt;
+        };
+
+        var model = llama.Model.load(model_path, .{
+            .n_gpu_layers = prof.optimal_config.n_gpu_layers,
+        }) catch {
+            std.debug.print("Error: Failed to load model\n", .{});
+            return error.ModelLoadFailed;
+        };
+        defer model.deinit();
+
+        const model_hash_val = model.getHash();
+        const conv_dir = try std.fmt.allocPrint(allocator,
+            "{s}/.cache/zell/conversations/{x}", .{ home, model_hash_val });
+        defer allocator.free(conv_dir);
+
+        std.debug.print("🧠 Memory Status for {s}\n", .{model_path});
+        std.debug.print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n", .{});
+        std.debug.print("Model Hash: {x}\n\n", .{model_hash_val});
+
+        // Count conversations
+        var dir = std.fs.cwd().openDir(conv_dir, .{ .iterate = true }) catch |err| {
+            if (err == error.FileNotFound) {
+                std.debug.print("Conversations: 0 (no memory yet)\n", .{});
+                std.debug.print("Status: Learning not started\n", .{});
+                std.debug.print("\nℹ️  Memory will begin collecting after first run\n", .{});
+                return;
+            }
+            return err;
+        };
+        defer dir.close();
+
+        var total_conversations: usize = 0;
+        var total_size: u64 = 0;
+        var file_count: usize = 0;
+
+        var iter = dir.iterate();
+        while (try iter.next()) |entry| {
+            if (entry.kind != .file) continue;
+            if (!std.mem.endsWith(u8, entry.name, ".jsonl")) continue;
+
+            const stat = try dir.statFile(entry.name);
+            total_size += stat.size;
+            file_count += 1;
+
+            // Count lines in file
+            const file = try dir.openFile(entry.name, .{});
+            defer file.close();
+
+            const content = try file.readToEndAlloc(allocator, 10 * 1024 * 1024);
+            defer allocator.free(content);
+
+            var lines = std.mem.splitScalar(u8, content, '\n');
+            while (lines.next()) |line| {
+                if (line.len > 0) total_conversations += 1;
+            }
+        }
+
+        std.debug.print("Conversations: {}\n", .{total_conversations});
+        std.debug.print("Log files: {}\n", .{file_count});
+        std.debug.print("Total size: {d:.2} MB\n\n", .{@as(f64, @floatFromInt(total_size)) / (1024.0 * 1024.0)});
+
+        // Check for auto-trained adapter
+        const adapter_path = try std.fmt.allocPrint(allocator,
+            "{s}/.cache/zell/lora/{x}_auto.lora", .{ home, model_hash_val });
+        defer allocator.free(adapter_path);
+
+        std.fs.cwd().access(adapter_path, .{}) catch |err| {
+            if (err == error.FileNotFound) {
+                const remaining = if (total_conversations >= 100) 0 else 100 - total_conversations;
+                std.debug.print("Auto-training: Not started\n", .{});
+                std.debug.print("Progress: {}/100 conversations ({}  more needed)\n", .{ total_conversations, remaining });
+                std.debug.print("\nℹ️  Auto-training will start after 100 conversations\n", .{});
+                return;
+            }
+            return err;
+        };
+
+        // Adapter exists - show info
+        const adapter_stat = try std.fs.cwd().statFile(adapter_path);
+        std.debug.print("✓ Auto-trained adapter: ACTIVE\n", .{});
+        std.debug.print("  Path: {s}\n", .{adapter_path});
+        std.debug.print("  Size: {d:.2} MB\n", .{@as(f64, @floatFromInt(adapter_stat.size)) / (1024.0 * 1024.0)});
+        std.debug.print("  Learned from: {} conversations\n", .{total_conversations});
+    } else {
+        // Show status for all models
+        const conv_base_dir = try std.fmt.allocPrint(allocator,
+            "{s}/.cache/zell/conversations", .{home});
+        defer allocator.free(conv_base_dir);
+
+        var base_dir = std.fs.cwd().openDir(conv_base_dir, .{ .iterate = true }) catch |err| {
+            if (err == error.FileNotFound) {
+                std.debug.print("🧠 No memory collected yet\n", .{});
+                std.debug.print("\nℹ️  Run 'zell run <model> \"prompt\"' to start collecting conversations\n", .{});
+                return;
+            }
+            return err;
+        };
+        defer base_dir.close();
+
+        std.debug.print("🧠 Memory Status (All Models)\n", .{});
+        std.debug.print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n", .{});
+
+        var model_count: usize = 0;
+        var base_iter = base_dir.iterate();
+        while (try base_iter.next()) |model_entry| {
+            if (model_entry.kind != .directory) continue;
+            model_count += 1;
+
+            std.debug.print("Model Hash: {s}\n", .{model_entry.name});
+
+            var model_dir = try base_dir.openDir(model_entry.name, .{ .iterate = true });
+            defer model_dir.close();
+
+            var total_conversations: usize = 0;
+            var total_size: u64 = 0;
+
+            var log_iter = model_dir.iterate();
+            while (try log_iter.next()) |log_entry| {
+                if (log_entry.kind != .file) continue;
+                if (!std.mem.endsWith(u8, log_entry.name, ".jsonl")) continue;
+
+                const stat = try model_dir.statFile(log_entry.name);
+                total_size += stat.size;
+
+                const file = try model_dir.openFile(log_entry.name, .{});
+                defer file.close();
+
+                const content = try file.readToEndAlloc(allocator, 10 * 1024 * 1024);
+                defer allocator.free(content);
+
+                var lines = std.mem.splitScalar(u8, content, '\n');
+                while (lines.next()) |line| {
+                    if (line.len > 0) total_conversations += 1;
+                }
+            }
+
+            std.debug.print("  Conversations: {}\n", .{total_conversations});
+            std.debug.print("  Size: {d:.2} MB\n", .{@as(f64, @floatFromInt(total_size)) / (1024.0 * 1024.0)});
+
+            // Check for adapter
+            const model_hash_str = model_entry.name;
+            const adapter_path = try std.fmt.allocPrint(allocator,
+                "{s}/.cache/zell/lora/{s}_auto.lora", .{ home, model_hash_str });
+            defer allocator.free(adapter_path);
+
+            std.fs.cwd().access(adapter_path, .{}) catch |err| {
+                if (err == error.FileNotFound) {
+                    std.debug.print("  Adapter: Not trained yet ({}/100)\n\n", .{total_conversations});
+                } else {
+                    return err;
+                }
+                continue;
+            };
+
+            std.debug.print("  Adapter: ✓ ACTIVE\n\n", .{});
+        }
+
+        if (model_count == 0) {
+            std.debug.print("No models with memory yet\n", .{});
+        }
+    }
+}
