+/// Clear conversation memory
+fn clearMemory(allocator: std.mem.Allocator, model_path_opt: ?[]const u8) !void {
+    const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+
+    if (model_path_opt) |model_path| {
+        // Clear memory for specific model
+        try validateModelPath(model_path);
+
+        const prof = optimizer.loadOptimizedProfile(allocator, model_path) catch {
+            std.debug.print("Error: Model not built. Run 'zell build {s}' first.\n", .{model_path});
+            return error.ModelNotBuilt;
+        };
+
+        var model = llama.Model.load(model_path, .{
+            .n_gpu_layers = prof.optimal_config.n_gpu_layers,
+        }) catch {
+            std.debug.print("Error: Failed to load model\n", .{});
+            return error.ModelLoadFailed;
+        };
+        defer model.deinit();
+
+        const model_hash_val = model.getHash();
+
+        // Delete conversation directory
+        const conv_dir = try std.fmt.allocPrint(allocator,
+            "{s}/.cache/zell/conversations/{x}", .{ home, model_hash_val });
+        defer allocator.free(conv_dir);
+
+        std.fs.cwd().deleteTree(conv_dir) catch |err| {
+            if (err == error.FileNotFound) {
+                std.debug.print("No memory to clear for this model\n", .{});
+                return;
+            }
+            return err;
+        };
+
+        // Delete auto-trained adapter
+        const adapter_path = try std.fmt.allocPrint(allocator,
+            "{s}/.cache/zell/lora/{x}_auto.lora", .{ home, model_hash_val });
+        defer allocator.free(adapter_path);
+
+        std.fs.cwd().deleteFile(adapter_path) catch |err| {
+            if (err != error.FileNotFound) return err;
+        };
+
+        std.debug.print("✓ Cleared all memory for {s}\n", .{model_path});
+        std.debug.print("  - Deleted conversation logs\n", .{});
+        std.debug.print("  - Deleted auto-trained adapter (if existed)\n", .{});
+    } else {
+        // Clear all memory
+        const conv_base_dir = try std.fmt.allocPrint(allocator,
+            "{s}/.cache/zell/conversations", .{home});
+        defer allocator.free(conv_base_dir);
+
+        std.fs.cwd().deleteTree(conv_base_dir) catch |err| {
+            if (err != error.FileNotFound) return err;
+        };
+
+        const lora_dir = try std.fmt.allocPrint(allocator,
+            "{s}/.cache/zell/lora", .{home});
+        defer allocator.free(lora_dir);
+
+        std.fs.cwd().deleteTree(lora_dir) catch |err| {
+            if (err != error.FileNotFound) return err;
+        };
+
+        std.debug.print("✓ Cleared ALL conversation memory\n", .{});
+    }
+}
